generated_oml:
// C3: Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor (I_M) measuring instantaneous motor current for friction identification"
    DTDFVocab:producedData DataTransmittedMotorCurrent
]

instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor encoder mounted directly on motor providing motor shaft angular position (r_M) and velocity"
    DTDFVocab:producedData DataTransmittedMotorEncoder
]

instance SecondaryEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder positioned behind the gearbox delivering gearbox output shaft angle (r_out) and intermediate shaft angle (r_G)"
    DTDFVocab:producedData DataTransmittedSecondaryEncoder
]

// C4: Physical‑to‑virtual interaction (DataTransmitted)
instance DataTransmittedMotorCurrent : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance DataTransmittedMotorEncoder : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

instance DataTransmittedSecondaryEncoder : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SecondaryEncoder
]

// C10: Data (measured traces)
instance MeasuredCurrentData : DTDFVocab:Data [
    base:desc "Measured time‑series of motor current I_M used for static, kinetic and viscous friction estimation"
    DTDFVocab:fromData DataTransmittedMotorCurrent
    DTDFVocab:inputTo MQTTBroker
]

instance MeasuredMotorEncoderData : DTDFVocab:Data [
    base:desc "Measured motor shaft angle r_M and derived angular velocity for torque calculation"
    DTDFVocab:fromData DataTransmittedMotorEncoder
    DTDFVocab:inputTo MQTTBroker
]

instance MeasuredSecondaryEncoderData : DTDFVocab:Data [
    base:desc "Measured gearbox intermediate angle r_G and output angle r_out to compute elasticity and torque transmission"
    DTDFVocab:fromData DataTransmittedSecondaryEncoder
    DTDFVocab:inputTo MQTTBroker
]

// C11: Enablers (technological tools)
instance MQTTBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker streaming live sensor traces (I_M, r_M, r_G, r_out) from the robot to the digital shadow"
    DTDFVocab:enables RealTimeDashboardVisualization, FrictionIdentificationService, ParameterEstimationService
]

instance SimulinkEngine : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink execution environment for running friction models (Coulomb‑Viscous, Stribeck, Dahl, LuGre) and generating simulated traces"
    DTDFVocab:enables SimulationModelExecutionService
]

instance SysMLTool : DTDFVocab:Enabler [
    base:desc "SysML modeling tool creating block definition and internal block diagrams of motor, gearwheel and cycloidal gearbox"
    DTDFVocab:enables EngineeringModelRepositoryService
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "AAS providing standardized representation of engineering and simulation models for integration in the digital twin"
    DTDFVocab:enables ModelIntegrationService
]

instance SINUMERIKController : DTDFVocab:Enabler [
    base:desc "Siemens SINUMERIK 840D controller receiving updated friction parameters for model‑based motion‑control improvement"
    DTDFVocab:enables MotionControlImprovementService
]

instance DashboardApp : DTDFVocab:Enabler [
    base:desc "Unified dashboard application visualizing real‑time friction loss, model performance and control insights"
    DTDFVocab:enables RealTimeDashboardVisualization
]

// C6: Services
instance RealTimeDashboardVisualization : DTDFVocab:Service [
    base:desc "Real‑time dashboard visualization of friction loss, model performance and controller feedback"
    DTDFVocab:provides FrictionLossInsight, ModelPerformanceInsight
]

instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Continuous identification of static, kinetic and viscous friction from streamed sensor data"
    DTDFVocab:provides FrictionParameterUpdateAction
]

instance ParameterEstimationService : DTDFVocab:Service [
    base:desc "Parameter estimation for white‑box and black‑box friction models (Coulomb‑Viscous, Stribeck, Dahl, LuGre)"
    DTDFVocab:provides ParameterEstimationInsight
]

instance MotionControlImprovementService : DTDFVocab:Service [
    base:desc "Model‑based motion‑control improvement by feeding estimated friction parameters back to the SINUMERIK controller"
    DTDFVocab:provides ControllerParameterUpdateAction
]

instance SimulationModelExecutionService : DTDFVocab:Service [
    base:desc "Execution of MATLAB/Simulink friction models to generate simulated torque and angular‑velocity traces"
    DTDFVocab:provides SimulatedFrictionDataInsight
]

instance EngineeringModelRepositoryService : DTDFVocab:Service [
    base:desc "Repository service for SysML engineering models of motor, gearwheel and cycloidal gearbox"
    DTDFVocab:provides EngineeringModelAvailabilityInsight
]

instance ModelIntegrationService : DTDFVocab:Service [
    base:desc "Integration of engineering and simulation models into the digital twin via Asset Administration Shells"
    DTDFVocab:provides ModelIntegrationInsight
]

// C10: Models
instance SysMLMotorModel : DTDFVocab:Model [
    base:desc "SysML block definition diagram representing the motor component of the first axis"
    DTDFVocab:inputTo SysMLTool
]

instance SysMLGearwheelModel : DTDFVocab:Model [
    base:desc "SysML internal block diagram describing the gearwheel gearbox geometry and kinematics"
    DTDFVocab:inputTo SysMLTool
]

instance SysMLCycloidalGearboxModel : DTDFVocab:Model [
    base:desc "SysML model of the cycloidal gearbox capturing elasticity and torque transmission characteristics"
    DTDFVocab:inputTo SysMLTool
]

instance SimulinkCoulombViscousModel : DTDFVocab:Model [
    base:desc "Simulink friction model implementing Coulomb and viscous friction components"
    DTDFVocab:inputTo SimulinkEngine
]

instance SimulinkStribeckModel : DTDFVocab:Model [
    base:desc "Simulink Stribeck friction model for static to kinetic transition"
    DTDFVocab:inputTo SimulinkEngine
]

instance SimulinkDahlModel : DTDFVocab:Model [
    base:desc "Simulink Dahl model capturing pre‑slip friction behavior"
    DTDFVocab:inputTo SimulinkEngine
]

instance SimulinkLuGreModel : DTDFVocab:Model [
    base:desc "Simulink LuGre model representing dynamic friction with internal state"
    DTDFVocab:inputTo SimulinkEngine
]

// C10: Simulated data (output of simulation models)
instance SimulatedMotorTrace : DTDFVocab:Data [
    base:desc "Simulated motor shaft torque and angular velocity (^r_M) generated by Simulink friction models"
    DTDFVocab:inputTo SimulinkEngine
    DTDFVocab:fromData DataTransmittedMotorEncoder
]

instance SimulatedGearboxTrace : DTDFVocab:Data [
    base:desc "Simulated gearbox intermediate torque and velocity (^r_G) from Simulink models"
    DTDFVocab:inputTo SimulinkEngine
    DTDFVocab:fromData DataTransmittedSecondaryEncoder
]

instance SimulatedOutputTrace : DTDFVocab:Data [
    base:desc "Simulated output shaft torque and velocity (^r_out) produced by Simulink friction models"
    DTDFVocab:inputTo SimulinkEngine
    DTDFVocab:fromData DataTransmittedSecondaryEncoder
]

// C17: Insights
instance FrictionLossInsight : DTDFVocab:Insight [
    base:desc "Dashboard insight showing current friction loss magnitude derived from identified parameters"
]

instance ModelPerformanceInsight : DTDFVocab:Insight [
    base:desc "Insight on how well the selected friction model matches measured data"
]

instance ParameterEstimationInsight : DTDFVocab:Insight [
    base:desc "Insight reporting confidence intervals and goodness‑of‑fit for estimated friction parameters"
]

instance SimulatedFrictionDataInsight : DTDFVocab:Insight [
    base:desc "Insight comparing simulated friction traces with measured data to validate model fidelity"
]

instance EngineeringModelAvailabilityInsight : DTDFVocab:Insight [
    base:desc "Insight confirming availability of up‑to‑date SysML models in the AAS repository"
]

instance ModelIntegrationInsight : DTDFVocab:Insight [
    base:desc "Insight indicating successful integration of engineering and simulation models into the digital twin"
]

// C17: Actions
instance FrictionParameterUpdateAction : DTDFVocab:Action [
    base:desc "Automatic update of friction parameters in the digital twin after each identification cycle"
    DTDFVocab:IsAutomatic true
]

instance ControllerParameterUpdateAction : DTDFVocab:Action [
    base:desc "Feedback action sending refined friction parameters to the SINUMERIK controller for motion‑control improvement"
    DTDFVocab:IsAutomatic true
]

// C9: Environment (optional aggregation)
instance RobotFirstAxisEnvironment : DTDFVocab:Environment [
    base:contains MotorCurrentSensor, MotorEncoder, SecondaryEncoder, MQTTBroker, SimulinkEngine, SysMLTool, AssetAdministrationShell, SINUMERIKController, DashboardApp
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "None – the digital shadow does not send commands or data back to the robot; it is a one‑way data flow entity."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous real‑time operation synchronized with the robot’s sensor update rate (sensor sampling up to the robot’s maximum speed of 75 °/s); data are processed as they arrive."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A purpose‑driven digital shadow consisting of a Purpose element (FrictionDerivation), an Asset element (MABI robot first axis), multiple DataTraces, Processing components (Simulation_M, Simulation_GW, Simulation_GB) that consume input traces and produce simulated outputs, and a dashboard that aggregates and visualizes the results."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Operational (run‑time) stage – the digital shadow is created and used during robot operation to improve control accuracy."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Full traceability of each DataPoint to its source and processing model; continuous re‑identification of friction parameters to account for wear, tool changes, and temperature; validation by comparing simulated friction‑adjusted outputs with measured reference data."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Data are transmitted from the robot to the digital shadow over MQTT; the digital shadow consumes these MQTT topics to build its DataTraces."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of the Asset Administration Shell (AAS) standard for model integration and representation of the asset within the digital shadow."
]
